        text: modelType === "llm" ? "\u672A\u627E\u5230\u5BF9\u8BDD\u6A21\u578B\uFF0C\u8BF7\u7528 ollama pull \u5B89\u88C5" : "\u672A\u627E\u5230\u5411\u91CF\u6A21\u578B\uFF0C\u8BF7\u5B89\u88C5\u5982 nomic-embed-text"
